#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define BLOCK_SIZE 16
#define BLOCK_SIZE_C BLOCK_SIZE
#define BLOCK_SIZE_R BLOCK_SIZE

#define STR_SIZE 256

#define MAX_PD (3.0e6f)

#define PRECISION 0.001f
#define SPEC_HEAT_SI 1.75e6f
#define K_SI 100.0f

#define FACTOR_CHIP 0.5f

#define amb_temp 80.0f

__kernel void hotspot(
    const int num_iterations,
    __global const float* power,
    __global const float* temp_in,
    __global float* temp_out,
    const int col,
    const int row,
    const int borderCols,
    const int borderRows,
    const float Cap,
    const float Rx,
    const float Ry,
    const float Rz,
    const float step)
{
    int global_row = get_global_id(1);
    int global_col = get_global_id(0);

    int total_cols = col;
    int total_rows = row;

    int r_start = global_row * BLOCK_SIZE_R;
    int c_start = global_col * BLOCK_SIZE_C;

    int r_end = r_start + BLOCK_SIZE_R;
    int c_end = c_start + BLOCK_SIZE_C;

    if (r_end > total_rows) r_end = total_rows;
    if (c_end > total_cols) c_end = total_cols;

    float Cap_1 = step / Cap;
    float Rx_1 = 1.0f / Rx;
    float Ry_1 = 1.0f / Ry;
    float Rz_1 = 1.0f / Rz;

    for (int iter = 0; iter < num_iterations; iter++) {
        barrier(CLK_GLOBAL_MEM_FENCE);

        for (int r = r_start; r < r_end; r++) {
            for (int c = c_start; c < c_end; c++) {
                int idx = r * total_cols + c;
                float delta = 0.0f;

                // Border conditions
                if (r == 0 || c == 0 || r == total_rows - 1 || c == total_cols - 1) {
                    if (r == 0 && c == 0) {
                        delta = Cap_1 * (power[0] +
                            (temp_in[1] - temp_in[0]) * Rx_1 +
                            (temp_in[total_cols] - temp_in[0]) * Ry_1 +
                            (amb_temp - temp_in[0]) * Rz_1);
                    }
                    else if (r == 0 && c == total_cols - 1) {
                        delta = Cap_1 * (power[c] +
                            (temp_in[c - 1] - temp_in[c]) * Rx_1 +
                            (temp_in[c + total_cols] - temp_in[c]) * Ry_1 +
                            (amb_temp - temp_in[c]) * Rz_1);
                    }
                    else if (r == total_rows - 1 && c == total_cols - 1) {
                        delta = Cap_1 * (power[r * total_cols + c] +
                            (temp_in[r * total_cols + c - 1] - temp_in[r * total_cols + c]) * Rx_1 +
                            (temp_in[(r - 1) * total_cols + c] - temp_in[r * total_cols + c]) * Ry_1 +
                            (amb_temp - temp_in[r * total_cols + c]) * Rz_1);
                    }
                    else if (r == total_rows - 1 && c == 0) {
                        delta = Cap_1 * (power[r * total_cols] +
                            (temp_in[r * total_cols + 1] - temp_in[r * total_cols]) * Rx_1 +
                            (temp_in[(r - 1) * total_cols] - temp_in[r * total_cols]) * Ry_1 +
                            (amb_temp - temp_in[r * total_cols]) * Rz_1);
                    }
                    else if (r == 0) {
                        delta = Cap_1 * (power[c] +
                            (temp_in[c + 1] + temp_in[c - 1] - 2.0f * temp_in[c]) * Rx_1 +
                            (temp_in[total_cols + c] - temp_in[c]) * Ry_1 +
                            (amb_temp - temp_in[c]) * Rz_1);
                    }
                    else if (c == total_cols - 1) {
                        delta = Cap_1 * (power[r * total_cols + c] +
                            (temp_in[(r + 1) * total_cols + c] + temp_in[(r - 1) * total_cols + c] - 2.0f * temp_in[r * total_cols + c]) * Ry_1 +
                            (temp_in[r * total_cols + c - 1] - temp_in[r * total_cols + c]) * Rx_1 +
                            (amb_temp - temp_in[r * total_cols + c]) * Rz_1);
                    }
                    else if (r == total_rows - 1) {
                        delta = Cap_1 * (power[r * total_cols + c] +
                            (temp_in[r * total_cols + c + 1] + temp_in[r * total_cols + c - 1] - 2.0f * temp_in[r * total_cols + c]) * Rx_1 +
                            (temp_in[(r - 1) * total_cols + c] - temp_in[r * total_cols + c]) * Ry_1 +
                            (amb_temp - temp_in[r * total_cols + c]) * Rz_1);
                    }
                    else if (c == 0) {
                        delta = Cap_1 * (power[r * total_cols] +
                            (temp_in[(r + 1) * total_cols] + temp_in[(r - 1) * total_cols] - 2.0f * temp_in[r * total_cols]) * Ry_1 +
                            (temp_in[r * total_cols + 1] - temp_in[r * total_cols]) * Rx_1 +
                            (amb_temp - temp_in[r * total_cols]) * Rz_1);
                    }
                    temp_out[idx] = temp_in[idx] + delta;
                }
                else {
                    // Interior points
                    delta = Cap_1 * (power[idx] +
                        (temp_in[(r + 1) * total_cols + c] + temp_in[(r - 1) * total_cols + c] - 2.0f * temp_in[idx]) * Ry_1 +
                        (temp_in[r * total_cols + c + 1] + temp_in[r * total_cols + c - 1] - 2.0f * temp_in[idx]) * Rx_1 +
                        (amb_temp - temp_in[idx]) * Rz_1);
                    temp_out[idx] = temp_in[idx] + delta;
                }
            }
        }
        barrier(CLK_GLOBAL_MEM_FENCE);

        // Swap pointers for next iteration
        __global const float* temp_tmp = temp_in;
        temp_in = temp_out;
        temp_out = (__global float*)temp_tmp;
    }
}
